import { db } from '../db';

export class GitCompatibilityLayer {
  static hasManagedAccounts(serverId: string): boolean {
    const row = db
      .prepare('SELECT COUNT(*) as count FROM server_git_accounts WHERE server_id = ?')
      .get(serverId) as { count: number } | undefined;
    return (row?.count ?? 0) > 0;
  }

  static isLegacyMode(serverId: string): boolean {
    return !this.hasManagedAccounts(serverId);
  }

  static getDefaultAccountId(serverId: string): string | null {
    const row = db
      .prepare(
        `
        SELECT git_account_id
        FROM server_git_accounts
        WHERE server_id = ?
        ORDER BY is_default DESC, created_at ASC
        LIMIT 1
      `
      )
      .get(serverId) as { git_account_id: string } | undefined;
    return row?.git_account_id ?? null;
  }
}
